import React from 'react';

function Timeline({ measures = 16 }) {
  const ticks = Array.from({ length: measures }, (_, i) => i + 1);
  return (
    <div className="timeline">
      {ticks.map((t) => (
        <div className="timeline-tick" key={t}>Bar {t}</div>
      ))}
    </div>
  );
}

export default Timeline;
